import './styles.css';
import App from './App';
import { createRoot, hydrateRoot } from 'react-dom/client';

const container = document.getElementById('root');

if (container) {
  if (container.hasChildNodes()) {
    hydrateRoot(container, <App />);
  } else {
    createRoot(container).render(<App />);
  }
}

if (module.hot) {
  module.hot.accept();
}
